    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    static char timestamp[64]; // Static to preserve across calls
    strftime(timestamp, sizeof(timestamp)-1, "%Y-%m-%d %H:%M:%S", t);

    static char log_string[256]; // Static to preserve across calls
    snprintf(log_string, sizeof(log_string)-1, "%s, UV Index: %u, ALS: %u, IR: %u\n", timestamp, uv_index, als, ir);
    return log_string;
}

