        return -1000;
    }

    // Convert to Celsius (LM75B returns temperature in 0.5°C increments)
    float temperature = (float)raw_temp * 0.5;

    // Validate the temperature reading
    if (temperature < -20 || temperature > 100) {
        fprintf(stderr, "Error: Invalid temperature reading: %.2f from sensor 0x%02X\n", temperature, address);
        return -1000; // Indicate error
    }

    return (int)temperature; // Return integer temperature
}

// Function to adjust fan speed using PWM
void adjust_fan_speed(int gpio_pin, int speed) {
    if (speed < 0) speed = 0;
    if (speed > 100) speed = 100;

    gpioPWM(gpio_pin, speed * 255 / 100); // pigpio uses 0-255
}

// Function to log data to the circular buffer
void log_data(float temperature, int fan_speed, time_t timestamp) {
    pthread_mutex_lock(&log_buffer.mutex);

    if (is_circular_buffer_full(&log_buffer)) {
        // Overwrite the oldest entry if the buffer is full
        log_buffer.tail = (log_buffer.tail + 1) % CIRCULAR_BUFFER_SIZE;
    }
    if (log_buffer.count < CIRCULAR_BUFFER_SIZE){
        log_buffer.count++;
    }

    LogEntry *entry = &log_buffer.buffer[log_buffer.head];
    entry->temperature = temperature;
    entry->fan_speed = fan_speed;
    entry->timestamp = timestamp;

    log_buffer.head = (log_buffer.head + 1) % CIRCULAR_BUFFER_SIZE;

    pthread_mutex_unlock(&log_buffer.mutex);
}

// Function to periodically write the contents of the circular buffer to a file
void *logging_thread(void *arg) {
    (void)arg; // Suppress unused parameter warning
    while (running) {
        sleep(LOGGING_INTERVAL);
        FILE *fp = fopen("thermal_log.txt", "a");
        if (fp == NULL) {
            perror("Error opening log file");
            continue;
        }

        pthread_mutex_lock(&log_buffer.mutex);

        int i = log_buffer.tail;
        int count = log_buffer.count;
        while (count > 0) {
            LogEntry *entry = &log_buffer.buffer[i];
            fprintf(fp, "%ld,%.2f,%d\n", entry->timestamp, entry->temperature, entry->fan_speed);
            i = (i + 1) % CIRCULAR_BUFFER_SIZE;
            count--;
        }

        pthread_mutex_unlock(&log_buffer.mutex);

        fclose(fp);
    }
    return NULL;
}

// Signal handler for graceful shutdown
void cleanup(int signal) {
    printf("Cleaning up and exiting...\n");
    running = false;

    // Stop PWM signals on all fan GPIOs
    for (int i = 0; i < NUM_SENSORS; i++) {
        gpioPWM(sensor_fan_map[i].gpio_pin, 0);
    }

    // Close I2C device
    close(i2c_fd);

    // Stop pigpio
    gpioTerminate();

    // Destroy mutex
    pthread_mutex_destroy(&log_buffer.mutex);

    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes for PWM
    for (int i = 0; i < NUM_SENSORS; i++) {
        gpioSetMode(sensor_fan_map[i].gpio_pin, PI_OUTPUT);
        gpioSetPWMfrequency(sensor_fan_map[i].gpio_pin, PWM_FREQUENCY); // Not needed for software PWM
        gpioSetPWMrange(sensor_fan_map[i].gpio_pin, 255); // Set PWM range to 255
    }

    // Open I2C bus
    char filename[20];
    snprintf(filename, 19, "/dev/i2c-%d", I2C_BUS);
    i2c_fd = open(filename, O_RDWR);
    if (i2c_fd < 0) {
        perror("Error: Could not open I2C bus");
        gpioTerminate();
        return 1;
    }

    // Initialize circular buffer
    initialize_circular_buffer(&log_buffer);

    // Create logging thread
    pthread_t logging_thread_id;
    if (pthread_create(&logging_thread_id, NULL, logging_thread, NULL) != 0) {
        perror("Error creating logging thread");
        close(i2c_fd);
        gpioTerminate();
        pthread_mutex_destroy(&log_buffer.mutex);
        return 1;
    }

    // Set up signal handlers
    signal(SIGINT, cleanup);
    signal(SIGTERM, cleanup);

    printf("Monitoring temperatures and controlling fans...\n");

    while (running) {
        for (int i = 0; i < NUM_SENSORS; i++) {
            int temperature = read_temperature(i2c_fd, sensor_fan_map[i].sensor_address);
            if (temperature != -1000) {
                int fan_speed = 0;

                // Proportional control algorithm
                if (temperature > TEMPERATURE_THRESHOLD_HIGH) {
                    fan_speed = 100; // Full speed
                } else if (temperature > TARGET_TEMPERATURE) {
                    fan_speed = (int)(((float)(temperature - TARGET_TEMPERATURE) / (TEMPERATURE_THRESHOLD_HIGH - TARGET_TEMPERATURE)) * 100);
                    if (fan_speed > 100) fan_speed = 100; // Ensure speed doesn't exceed 100%
                } else if (temperature < TEMPERATURE_THRESHOLD_LOW){
                    fan_speed = 0;
                } else {
                    fan_speed = 20; // Minimum speed
                }

                adjust_fan_speed(sensor_fan_map[i].gpio_pin, fan_speed);

                time_t now = time(NULL);
                log_data((float)temperature, fan_speed, now);

                printf("Sensor 0x%02X: Temperature = %d°C, Fan Speed (GPIO %d) = %d%%\n",
                       sensor_fan_map[i].sensor_address, temperature, sensor_fan_map[i].gpio_pin, fan_speed);
            }
        }

        sleep(1); // Check temperatures every 1 second
    }

    // Join the logging thread
    pthread_join(logging_thread_id, NULL);

    // Cleanup resources before exiting
    cleanup(0);

    return 0;
}

