        perror("Failed to open the pwm device");
        exit(1);
    }

    // Set I2C slave address
    if (ioctl(file_i2c, I2C_SLAVE, LM75B_ADDR) < 0) {
        perror("Failed to acquire bus access and/or talk to slave.\n");
        exit(1);
