    if (write(file_i2c, buffer, 1) != 1) {
        perror("Failed to write to the i2c bus.");
        exit(1);
    }

    if (read(file_i2c, buffer, 2) != 2) {
        perror("Failed to read from the i2c bus.");
        exit(1);
