static FILE *logFile = NULL;

// Function prototypes
float readTemperature();
void controlFan(float temperature);
void logData(float temperature, int fanSpeed);
void signalHandler(int signal);

// Function to read temperature from MAX31855 via SPI
float readTemperature() {
    uint8_t data[4];
    int result;

    result = wiringPiSPIDataRW(SPI_CHANNEL, data, 4);
    if (result == -1) {
        fprintf(stderr, "SPI read failed: %s\n", strerror(errno));
        return -100.0; // Indicate error
    }

    // Extract temperature data (12 bits)
    int16_t rawTemperature = ((data[0] << 8) | data[1]) >> 4;

    // Check for fault conditions
    if (data[3] & 0x04) {
        fprintf(stderr, "MAX31855 Fault: Thermocouple not connected or shorted to GND/VCC\n");
        return -100.0; // Indicate error
    }
    if (data[3] & 0x02) {
        fprintf(stderr, "MAX31855 Fault: Thermocouple not connected or shorted to GND/VCC\n");
        return -100.0; // Indicate error
    }

    // Convert to Celsius
    float temperature = (float)rawTemperature * 0.25;

    return temperature;
}

// Function to control the fan speed via PWM
void controlFan(float temperature) {
    int fanSpeed;

    if (temperature > TEMP_THRESHOLD_HIGH) {
        fanSpeed = 100;
    } else if (temperature < TEMP_THRESHOLD_LOW) {
        fanSpeed = 0;
    } else {
        fanSpeed = (int)((temperature - TEMP_THRESHOLD_LOW) / (TEMP_THRESHOLD_HIGH - TEMP_THRESHOLD_LOW) * 100.0);
        if (fanSpeed < 0) fanSpeed = 0;
        if (fanSpeed > 100) fanSpeed = 100;
    }

    pwmWrite(FAN_GPIO_PIN, fanSpeed * 2.55); // Convert percentage to duty cycle (0-1023)
    logData(temperature, fanSpeed);
}

// Function to log data to a file
void logData(float temperature, int fanSpeed) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    if (logFile != NULL) {
        fprintf(logFile, "%s, Temperature: %.2f C, Fan Speed: %d%%\n", timestamp, temperature, fanSpeed);
        fflush(logFile); // Ensure data is written to disk immediately
    } else {
        fprintf(stderr, "Error: Log file not opened.\n");
    }
}

// Signal handler for graceful shutdown
void signalHandler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    keepRunning = 0;

    // Disable PWM
    pwmWrite(FAN_GPIO_PIN, 0);

    // Close log file
    if (logFile != NULL) {
        fclose(logFile);
    }

    exit(0);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "wiringPiSPISetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Configure GPIO18 as PWM output
    pinMode(FAN_GPIO_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS); // Mark:Space mode
    pwmSetRange(1024);      // 0-1023 range
    pwmSetClock(32);         // Set PWM clock (32 MHz / 32 = 1 MHz)

    // Open log file
    logFile = fopen(LOG_FILE, "a");
    if (logFile == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return 1;
    }

    // Register signal handler
    signal(SIGINT, signalHandler);
    signal(SIGTERM, signalHandler);

    printf("Temperature-controlled fan system started. Press Ctrl+C to exit.\n");

    while (keepRunning) {
        float temperature = readTemperature();
        if (temperature != -100.0) {
            controlFan(temperature);
            delay(500); // Read temperature every 500ms
        } else {
            // Handle SPI read error
            fprintf(stderr, "SPI read failed, retrying in 1 second...\n");
            delay(1000); // Wait before retrying
        }
    }

    return 0;
}

