// Define constants
#define FAN_PIN 1  // GPIO18 (WiringPi pin 1)
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1 MHz
#define MAX31855_DATA_SIZE 5 // 4 bytes of data + null terminator
#define SERVER_PORT 5000
#define SERVER_IP "127.0.0.1" // Localhost for testing
#define TEMPERATURE_THRESHOLD 30.0 // Temperature threshold in Celsius
#define MAX_RETRIES 3

// Global variables
FILE *logFile = NULL;
bool running = true;
int socket_desc;
struct sockaddr_in server_addr, client_addr;
socklen_t client_len = sizeof(client_addr);

// Function prototypes
float readTemperature();
int sendTemperature(float temperature);
int receiveFanSpeed(int *fanSpeed);
void setFanSpeed(int percentage);
void logData(time_t timestamp, float temperature, int fanSpeed);
void signalHandler(int signum);
int initializeServer();
int processClient(float temperature);

// Function to read temperature from MAX31855 via SPI
float readTemperature() {
    unsigned char data[MAX31855_DATA_SIZE];
    int retries = 0;

    while (retries < MAX_RETRIES) {
        if (wiringPiSPIDataRW(SPI_CHANNEL, data, MAX31855_DATA_SIZE) == -1) {
            fprintf(stderr, "SPI read failed (attempt %d): %s\n", retries + 1, strerror(errno));
            retries++;
            delay(10); // Short delay before retry
            continue;
        }

        // Check for errors in the status register (bit 0 of byte 3)
        if (data[3] & 0x07) {
            fprintf(stderr, "MAX31855 error: %s%s%s (attempt %d)\n",
                    (data[3] & 0x01) ? "Open circuit, " : "",
                    (data[3] & 0x02) ? "Short to GND, " : "",
                    (data[3] & 0x04) ? "Short to VCC, " : "",
                    retries + 1);
            retries++;
            delay(10); // Short delay before retry
            continue;
        }

        // Extract temperature data (bits 3-14 of byte 0 and byte 1)
        int16_t raw_temp = ((int16_t)data[0] << 6) | (data[1] >> 2);
        float temperature = (float)raw_temp / 64.0;
        return temperature;
    }

    fprintf(stderr, "MAX31855 read failed after %d retries. Returning -273.15\n", MAX_RETRIES);
    return -273.15; // Return absolute zero on failure
}

// Function to send temperature data via UDP
int sendTemperature(float temperature) {
    char message[50];
    snprintf(message, sizeof(message), "%.2f", temperature);

    if (sendto(socket_desc, message, strlen(message), 0, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        fprintf(stderr, "Send failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

