// Define GPIO pins
#define LOCK_1_GPIO 17
#define LOCK_2_GPIO 27
#define BUTTON_GPIO 4
#define PIR_GPIO 22

// Define lock activation duration (in milliseconds)
#define LOCK_DURATION 3000

// Global variables
FILE *logFile = NULL;
int lock1State = 0; // 0 = unlocked, 1 = locked
int lock2State = 0;

// Function prototypes
int initGPIO();
void toggleLocks();
void activateLock(int gpio, int duration_ms);
void logEvent(int gpio, const char *action);
void buttonCallback(int gpio, int level, uint32_t tick);
void motionCallback(int gpio, int level, uint32_t tick);
void signalHandler(int signal);

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize GPIO pins
    if (initGPIO() != 0) {
        fprintf(stderr, "GPIO initialisation failed\n");
        gpioTerminate();
        return 1;
    }

    // Open log file
    logFile = fopen("lock_events.log", "a");
    if (logFile == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        gpioTerminate();
        return 1;
    }

    // Set signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    printf("Door control system started. Press Ctrl+C to exit.\n");

    // Keep the program running
    while (1) {
        gpioDelay(100); // Reduce CPU usage
    }

    return 0;
}

// Initialize GPIO pins
int initGPIO() {
    // Set GPIO modes
    gpioSetMode(LOCK_1_GPIO, PI_OUTPUT);
    gpioSetMode(LOCK_2_GPIO, PI_OUTPUT);
    gpioSetMode(BUTTON_GPIO, PI_INPUT);
    gpioSetMode(PIR_GPIO, PI_INPUT);

    // Set pull-up resistor for the button
    gpioSetPullUpDown(BUTTON_GPIO, PI_PUD_UP);

    // Set callback function for the button (debouncing)
    if (gpioSetAlertFuncEx(BUTTON_GPIO, buttonCallback, NULL) != 0) {
        fprintf(stderr, "Error setting button callback\n");
        return 1;
    }

    // Set callback function for the PIR sensor
    if (gpioSetAlertFuncEx(PIR_GPIO, motionCallback, NULL) != 0) {
        fprintf(stderr, "Error setting motion callback\n");
        return 1;
    }

    return 0;
}

// Toggle the state of both door locks
void toggleLocks() {
    lock1State = !lock1State;
    lock2State = !lock2State;

    gpioWrite(LOCK_1_GPIO, lock1State);
    gpioWrite(LOCK_2_GPIO, lock2State);

    logEvent(LOCK_1_GPIO, lock1State ? "Lock 17 Activated (Button)" : "Lock 17 Deactivated (Button)");
    logEvent(LOCK_2_GPIO, lock2State ? "Lock 27 Activated (Button)" : "Lock 27 Deactivated (Button)");

    // Deactivate after 3 seconds if activated
    if (lock1State) {
        gpioDelay(LOCK_DURATION);
        lock1State = 0;
        gpioWrite(LOCK_1_GPIO, lock1State);
        logEvent(LOCK_1_GPIO, "Lock 17 Deactivated (Timeout)");
    }
    if (lock2State) {
        gpioDelay(LOCK_DURATION);
        lock2State = 0;
        gpioWrite(LOCK_2_GPIO, lock2State);
        logEvent(LOCK_2_GPIO, "Lock 27 Deactivated (Timeout)");
    }
}

// Activate a specific door lock for a given duration
void activateLock(int gpio, int duration_ms) {
    gpioWrite(gpio, 1); // Activate the lock
    logEvent(gpio, gpio == LOCK_1_GPIO ? "Lock 17 Activated (Motion)" : "Lock 27 Activated (Motion)");
    gpioDelay(duration_ms);
    gpioWrite(gpio, 0); // Deactivate the lock
    logEvent(gpio, gpio == LOCK_1_GPIO ? "Lock 17 Deactivated (Timeout)" : "Lock 27 Deactivated (Timeout)");
}

// Log an event to the log file
void logEvent(int gpio, const char *action) {
    if (logFile != NULL) {
        time_t t = time(NULL);
        struct tm tm = *localtime(&t);
        fprintf(logFile, "[%04d-%02d-%02d %02d:%02d:%02d] GPIO %d: %s\n",
                tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, gpio, action);
        fflush(logFile); // Ensure the log is written immediately
    } else {
        fprintf(stderr, "Error: Log file not opened!\n");
    }
}

// Callback function for the button
void buttonCallback(int gpio, int level, uint32_t tick) {
    if (gpio == BUTTON_GPIO && level == 0) { // Button pressed (LOW)
        logEvent(BUTTON_GPIO, "Button Press");
        toggleLocks();
    }
}

// Callback function for the PIR sensor
void motionCallback(int gpio, int level, uint32_t tick) {
    if (gpio == PIR_GPIO && level == 1) { // Motion detected (HIGH)
        logEvent(PIR_GPIO, "Motion Detected");
        activateLock(LOCK_1_GPIO, LOCK_DURATION);
        activateLock(LOCK_2_GPIO, LOCK_DURATION);
    }
}

// Signal handler for Ctrl+C
void signalHandler(int signal) {
    printf("Ctrl+C pressed. Exiting...\n");
    if (logFile != NULL) {
        fclose(logFile);
    }
    gpioTerminate();
    exit(0);
}

