    if(level == 0){
        printf("Switch is closed\n");
    }
    else{
        printf("Switch is open\n");
    }

    Event event;
    event.state = level == 0 ? '0' : '1';
    event.timestamp = rawtime;

    buffer[buffer_index % BUFFER_SIZE] = event;
    buffer_index++;
}

