    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialization failed\n");
        return 1;
    }

    gpioSetMode(GPIO_PIN, PI_INPUT);

    if (gpioSetAlertFunc(GPIO_PIN, callback) < 0) {
        fprintf(stderr, "Failed to register interrupt callback\n");
        return 2;
    }

    while(1){
        // Display last 10 events
        for(int i = (buffer_index < BUFFER_SIZE ? 0 : buffer_index - BUFFER_SIZE); i < buffer_index; i++) {
            printf("%c %s", buffer[i % BUFFER_SIZE].state, ctime(&buffer[i % BUFFER_SIZE].timestamp));
        }
        time_sleep(1);
    }

    gpioTerminate();
    return 0;
}
