    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    bh1750_t dev = bh1750_init(I2C_BUS, I2C_ADDR);
    if (dev < 0)
    {
        fprintf(stderr, "bh1750 initialisation failed\n");
        return 1;
    }

    FILE *file = fopen("light_log.txt", "w");
    if (file == NULL)
    {
        fprintf(stderr, "Failed to open file\n");
        return 1;
    }

