            fprintf(file, "%lu\n", lux);
            last_lux = lux;

            // Map the lux value to a brightness value between 0 and 255
            unsigned int brightness = (lux / 1000) * 255;
            gpioPWM(LED_PIN, brightness);
        }
    }

    fclose(file);
    bh1750_free(dev);
    gpioTerminate();

    return 0;
}
